RLTaskSchema::Runtime_targetEnum RLTaskSchema::toRuntime_targetEnum(const utility::string_t& value) const
{
    
    if (value == utility::conversions::to_string_t("cyberwave-rl")) {
        return Runtime_targetEnum::CYBERWAVE_RL;
    }
    
    if (value == utility::conversions::to_string_t("cyberwave-rl-experimental")) {
        return Runtime_targetEnum::CYBERWAVE_RL_EXPERIMENTAL;
    }
    
    throw std::invalid_argument("Invalid value for conversion to Runtime_targetEnum");
}


const utility::string_t RLTaskSchema::fromRuntime_targetEnum(const Runtime_targetEnum value) const
{
    switch(value)
    {
        
        case Runtime_targetEnum::CYBERWAVE_RL: return utility::conversions::to_string_t("cyberwave-rl");
        
        case Runtime_targetEnum::CYBERWAVE_RL_EXPERIMENTAL: return utility::conversions::to_string_t("cyberwave-rl-experimental");
        
    }
}

RLTaskSchema::Runtime_acceleratorEnum RLTaskSchema::toRuntime_acceleratorEnum(const utility::string_t& value) const
{
    
    if (value == utility::conversions::to_string_t("cpu")) {
        return Runtime_acceleratorEnum::CPU;
    }
    
    if (value == utility::conversions::to_string_t("gpu")) {
        return Runtime_acceleratorEnum::GPU;
    }
    
    throw std::invalid_argument("Invalid value for conversion to Runtime_acceleratorEnum");
}


const utility::string_t RLTaskSchema::fromRuntime_acceleratorEnum(const Runtime_acceleratorEnum value) const
{
    switch(value)
    {
        
        case Runtime_acceleratorEnum::CPU: return utility::conversions::to_string_t("cpu");
        
        case Runtime_acceleratorEnum::GPU: return utility::conversions::to_string_t("gpu");
        
    }
}


